async def execute(self, inputs):
    cond = bool(inputs.get('condition', False))
    data = inputs.get('data')

    self.log_info(f"Evaluating condition: {cond}")

    if cond:
        return {'on_true': data, 'on_false': None, 'result': True}
    else:
        return {'on_true': None, 'on_false': data, 'result': False}

def on_parameter_changed(self, name, value):
    if name == 'condition':
        cond = bool(value)
        data = self.get_parameter('data')
        self.log_info(f"Condition changed reactive: {cond}")
        if cond:
            self.set_output('on_true', data)
            self.set_output('on_false', None)
        else:
            self.set_output('on_true', None)
            self.set_output('on_false', data)
        self.set_output('result', cond)
